 15→import { parseArgs } from "node:util";
 16→import { serve } from "./serve.js";
 17→import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
 18→import { banner, c, blank, info, hint, success, error } from "./ui.js";
 19→
 20→function printHelp() {
 21→  banner();
 22→  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
 23→  blank();
 24→  console.log(`  ${c.bold("Commands:")}`);
 25→  console.log(`    ${c.dim("(none)")}        Auto-detect: launch desktop app or start server`);
