 31→  console.log(`    ${c.cyan("--host")}       Host to bind to ${c.dim("(default: localhost)")}`);
 32→  console.log(`    ${c.cyan("--open")}       Open browser after starting`);
 33→  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
 34→  blank();
 35→  console.log(`  ${c.bold("Examples:")}`);
 36→  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
 37→  console.log(`    ${c.dim("$")} deus serve -p 8080      ${c.dim("# server on port 8080")}`);
 38→  console.log(`    ${c.dim("$")} deus serve --open       ${c.dim("# server + open browser")}`);
 39→  console.log(`    ${c.dim("$")} deus desktop            ${c.dim("# install desktop app")}`);
 40→  blank();
 41→}
