111→export interface Spinner {
112→  /** Update the spinner text while it's running */
113→  update(text: string): void;
114→  /** Stop with a success message */
115→  succeed(text?: string): void;
116→  /** Stop with a failure message */
117→  fail(text?: string): void;
118→  /** Stop with a warning message */
119→  warn(text?: string): void;
120→  /** Stop with an info message */
121→  info(text?: string): void;
122→  /** Stop and clear the line */
123→  stop(): void;
124→}
