126→export function spinner(text: string): Spinner {
127→  let frameIdx = 0;
128→  let currentText = text;
129→  let stopped = false;
130→
131→  const stream = process.stderr;
132→
133→  function render() {
134→    if (stopped) return;
135→    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
136→    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
137→    frameIdx++;
138→  }
139→
140→  const interval = setInterval(render, SPINNER_INTERVAL);
141→  render();
142→
143→  function stop(symbol: string, finalText: string) {
144→    if (stopped) return;
145→    stopped = true;
146→    clearInterval(interval);
147→    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
148→  }
149→
150→  return {
151→    update(t: string) {
152→      currentText = t;
153→    },
154→    succeed(t?: string) {
155→      stop(c.green(sym.tick), t ?? currentText);
156→    },
157→    fail(t?: string) {
158→      stop(c.red(sym.cross), t ?? currentText);
159→    },
160→    warn(t?: string) {
161→      stop(c.yellow(sym.warning), t ?? currentText);
162→    },
163→    info(t?: string) {
164→      stop(c.blue(sym.info), t ?? currentText);
165→    },
166→    stop() {
167→      if (stopped) return;
168→      stopped = true;
169→      clearInterval(interval);
170→      stream.write(`\r${ESC}2K`);
171→    },
172→  };
173→}
