182→  const { padding = 1, borderColor = c.dim, width } = opts ?? {};
183→  const pad = " ".repeat(padding);
184→
185→  // Calculate width from content (strip ANSI for measurement)
186→  const stripped = lines.map(stripAnsi);
187→  const contentWidth = width ?? Math.max(...stripped.map((l) => l.length));
188→  const innerWidth = contentWidth + padding * 2;
189→
190→  const top = borderColor(`  ${sym.tl}${sym.h.repeat(innerWidth)}${sym.tr}`);
191→  const bot = borderColor(`  ${sym.bl}${sym.h.repeat(innerWidth)}${sym.br}`);
192→  const empty = borderColor(`  ${sym.v}`) + " ".repeat(innerWidth) + borderColor(sym.v);
193→
194→  console.log(top);
195→  console.log(empty);
196→  for (let i = 0; i < lines.length; i++) {
197→    const visible = stripped[i].length;
198→    const rightPad = " ".repeat(Math.max(0, contentWidth - visible));
199→    console.log(
200→      borderColor(`  ${sym.v}`) + pad + lines[i] + rightPad + pad + borderColor(sym.v)
201→    );
202→  }
203→  console.log(empty);
204→  console.log(bot);
205→}
