255→}
256→
257→// ── Progress Bar ─────────────────────────────────────────────────────
258→
259→const BAR_WIDTH = 30;
260→const BAR_FILLED = isUnicode ? "█" : "#";
261→const BAR_EMPTY = isUnicode ? "░" : ".";
262→
263→export function progressBar(current: number, total: number, label?: string): void {
264→  const pct = Math.min(1, current / total);
265→  const filled = Math.round(pct * BAR_WIDTH);
266→  const empty = BAR_WIDTH - filled;
267→  const bar = c.cyan(BAR_FILLED.repeat(filled)) + c.dim(BAR_EMPTY.repeat(empty));
268→  const pctStr = `${Math.round(pct * 100)}%`.padStart(4);
269→  const extra = label ? ` ${c.dim(label)}` : "";
270→  process.stderr.write(`\r${ESC}2K  ${bar} ${pctStr}${extra}`);
271→}
