278→// ── Utilities ────────────────────────────────────────────────────────
279→
280→/** Strip ANSI escape codes for length calculation */
281→function stripAnsi(str: string): string {
282→  // eslint-disable-next-line no-control-regex
283→  return str.replace(/\x1b\[[0-9;]*m/g, "");
284→}
