 52→export interface ServeOptions {
 53→  port: number;
 54→  host: string;
 55→  open: boolean;
 56→  dataDir?: string;
 57→}
 58→
 59→interface ProcessInfo {
 60→  process: ChildProcess;
 61→  name: string;
 62→}
 63→
 64→export async function serve(options: ServeOptions): Promise<void> {
 65→  const { port, host, open, dataDir } = options;
 66→
 67→  // Resolve paths to bundles
 68→  const paths = resolveBundlePaths();
 69→  if (!paths) {
 70→    error("Could not find Deus bundles.");
 71→    blank();
 72→    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 73→    blank();
 74→    process.exit(1);
 75→  }
 76→
 77→  // Resolve Node binary (handles Electron ABI mismatch in dev)
 78→  const nodeCmd = resolveNodeBinary();
 79→
 80→  // Resolve database
 81→  const dbPath = resolveDataDir(dataDir);
 82→  kv("Database", c.dim(dbPath));
 83→  blank();
 84→
 85→  // Track child processes for cleanup
 86→  const children: ProcessInfo[] = [];
 87→
 88→  function shutdown() {
 89→    blank();
 90→    hint("Shutting down...");
 91→    for (const child of children) {
 92→      if (!child.process.killed) child.process.kill("SIGTERM");
 93→    }
 94→    process.exit(0);
 95→  }
 96→  process.on("SIGINT", shutdown);
 97→  process.on("SIGTERM", shutdown);
 98→
 99→  // ── Step 1: Agent server ─────────────────────────────────────────
100→  const s1 = createSpinner("Starting agent server...");
101→  const agentServerUrl = await startProcess({
102→    name: "agent-server",
103→    command: nodeCmd,
104→    args: [paths.agentServer],
105→    env: { DATABASE_PATH: dbPath },
106→    waitFor: /LISTEN_URL=(.+)/,
107→    children,
108→  });
109→
110→  if (!agentServerUrl) {
111→    s1.fail("Agent server failed to start");
112→    blank();
113→    process.exit(1);
114→  }
115→  s1.succeed(`Agent server ${c.dim("ready")}`);
116→
117→  // ── Step 2: Backend ──────────────────────────────────────────────
118→  const s2 = createSpinner("Starting backend...");
119→  const backendPort = await startProcess({
120→    name: "backend",
121→    command: nodeCmd,
122→    args: [paths.backend],
123→    env: {
124→      AGENT_SERVER_URL: agentServerUrl,
125→      DATABASE_PATH: dbPath,
126→      PORT: "0",
127→    },
128→    waitFor: /\[BACKEND_PORT\](\d+)/,
129→    children,
130→  });
131→
132→  if (!backendPort) {
133→    s2.fail("Backend failed to start");
134→    blank();
135→    process.exit(1);
136→  }
137→  s2.succeed(`Backend ${c.dim("ready")}`);
138→
139→  // ── Step 3: Web server ───────────────────────────────────────────
140→  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));
141→
142→  const s3 = createSpinner("Starting web server...");
143→  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);
144→
145→  await new Promise<void>((resolve) => {
146→    webServer.listen(port, host, () => resolve());
147→  });
148→
149→  if (hasFrontend) {
150→    s3.succeed(`Web UI ${c.dim("ready")}`);
151→  } else {
152→    s3.warn(`Web UI ${c.dim("— frontend not built, API-only mode")}`);
153→  }
154→
155→  // ── Ready! ───────────────────────────────────────────────────────
156→  blank();
157→
158→  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
159→  box([c.bold(c.brightWhite(url))], { borderColor: c.cyan, width: 36 });
160→
161→  blank();
162→  kv("Local", c.cyan(url), 10);
163→
164→  // Show network URL if binding to all interfaces or a specific host
165→  const lanIp = getLanIp();
166→  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
167→    kv("Network", c.dim(`http://${lanIp}:${port}`), 10);
168→  }
169→
170→  blank();
171→  divider("Remote Access");
172→  blank();
173→  hint("To access from your phone or another computer:");
174→  blank();
175→  console.log(`    1. Open  ${c.cyan(c.underline("app.rundeus.com"))}`);
176→  console.log(`    2. Pair your device with this server`);
177→  blank();
178→  hint(`Or enable remote access in Settings ${sym.arrow} Remote Access`);
179→  blank();
180→  divider();
181→  blank();
182→  hint(`Press ${c.dim("Ctrl+C")} to stop`);
183→  blank();
184→
185→  if (open) {
186→    openBrowser(url);
187→  }
188→
189→  // Keep the process alive
190→  await new Promise(() => {});
191→}
