478→function openBrowser(url: string) {
479→  const os = platform();
480→  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
481→  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
482→}
