 51→/** Check if a display/GUI is available. */
 52→export function hasDisplay(): boolean {
 53→  const os = platform();
 54→  if (process.env.CI || process.env.DOCKER || existsSync("/.dockerenv")) return false;
 55→  if (os === "darwin") return true;
 56→  if (os === "win32") return !process.env.SSH_CONNECTION;
